@import '../../utils/control-density.css';
@import '../../utils/focus-ring.css';
@import '../../utils/interaction-fill.css';
@import '../../utils/control-inactive.css';

:host {
  display: block;
  --_tab-group-surface-border: var(--color-border-tertiary);
  --_tab-group-divider: var(--color-border-secondary);
}

:host(.tab-group-host--on-medium) {
  --_tab-group-surface-border: var(--color-border-on-medium-background-tertiary);
  --_tab-group-divider: var(--color-border-on-medium-background-secondary);
}

:host(.tab-group-host--on-bold) {
  --_tab-group-surface-border: var(--color-border-on-bold-background-tertiary);
  --_tab-group-divider: var(--color-border-on-bold-background-secondary);
}

:host(.tab-group-host--on-strong) {
  --_tab-group-surface-border: var(--color-border-on-strong-background-tertiary);
  --_tab-group-divider: var(--color-border-on-strong-background-secondary);
}

:host(.tab-group-host--on-translucent) {
  --_tab-group-surface-border: var(--color-translucent-border-tertiary);
  --_tab-group-divider: var(--color-translucent-border-secondary);
}

:host(.tab-group-host--on-inverted) {
  --_tab-group-surface-border: var(--color-inverted-border-tertiary);
  --_tab-group-divider: var(--color-inverted-border-secondary);
}

:host(.tab-group-host--on-media) {
  --_tab-group-surface-border: var(--color-media-border-tertiary);
  --_tab-group-divider: var(--color-media-border-secondary);
}

:host(.tab-group-host--on-always-dark) {
  --_tab-group-surface-border: var(--color-always-dark-border-tertiary);
  --_tab-group-divider: var(--color-always-dark-border-secondary);
}

.tab-list {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
  position: relative;
  width: max-content;
  max-width: 100%;
  height: var(--dimension-size-400);
  padding: calc(var(--dimension-space-050) - var(--dimension-stroke-width-012));
  background-color: var(--color-background-secondary);
  border: var(--dimension-stroke-width-012) solid var(--_tab-group-surface-border);
  border-radius: var(--dimension-radius-half);
  box-sizing: border-box;
}

:host(.tab-group-host--surface) .tab-list {
  background-color: transparent;
}

.tab {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--ds-control-gap);
  padding: 0 var(--ds-control-padding-inline);
  background-color: transparent;
  border: none;
  border-radius: var(--dimension-radius-half);
  cursor: pointer;
  -webkit-user-select: none;
  user-select: none;
  color: var(--color-foreground-secondary);
  transition: color var(--effect-motion-short-2);
  flex-shrink: 0;
  height: var(--ds-control-height);
  min-width: var(--dimension-size-400);
  box-sizing: border-box;
  --_dot: var(--color-foreground-bold-brand);
  /* Hover/press: `.ds-interaction-fill` — fills cover full 24px box (no layout border). */
}

.tab--selected {
  color: var(--color-foreground-primary);
  background-color: var(--color-background-primary);
  /* Inset stroke on interaction-fill ::after — stays above hover wash. */
  --ds-interaction-border-width: var(--dimension-stroke-width-012);
  --ds-interaction-border-color: var(--_tab-group-surface-border);
}

:host(.tab-group-host--surface) .tab--selected {
  background-color: var(--ds-interaction-active);
}

.tab--selected:not(.ds-interaction-fill) {
  box-shadow: inset 0 0 0 var(--ds-interaction-border-width) var(--ds-interaction-border-color);
}

/* Inactive: `.ds-control-inactive` (25% opacity) — applied via class in TSX. */

.tab__content {
  position: relative;
  z-index: 2;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--ds-control-gap);
  min-width: 0;
}

.tab__content--dot {
  padding-right: var(--dimension-space-050);
}

.tab__label {
  padding: 0 var(--ds-control-label-inset);
  white-space: nowrap;
}

.tab__icon {
  flex-shrink: 0;
}

.tab__dot {
  position: absolute;
  top: 0;
  right: 0;
  z-index: 2;
  pointer-events: none;
}

.on-medium {
  color: var(--color-foreground-on-medium-background-secondary);
}

.on-medium.tab--selected { color: var(--color-foreground-on-medium-background-primary); }

.on-bold {
  color: var(--color-foreground-on-bold-background-secondary);
}

.on-bold.tab--selected { color: var(--color-foreground-on-bold-background-primary); }

.on-strong {
  color: var(--color-foreground-on-strong-background-secondary);
}

.on-strong.tab--selected { color: var(--color-foreground-on-strong-background-primary); }

.on-translucent { color: var(--color-translucent-foreground-secondary); }

.on-translucent.tab--selected { color: var(--color-translucent-foreground-primary); }

.on-inverted { color: var(--color-inverted-foreground-secondary); }

.on-inverted.tab--selected { color: var(--color-inverted-foreground-primary); }

.on-media { color: var(--color-media-foreground-secondary); }

.on-media.tab--selected { color: var(--color-media-foreground-primary); }

.on-always-dark {
  color: var(--color-always-dark-foreground-secondary);
}

.on-always-dark.tab--selected { color: var(--color-always-dark-foreground-primary); }

.tab-divider {
  display: flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  width: var(--dimension-stroke-width-012);
  align-self: center;
  padding: 0;
  flex-shrink: 0;
  pointer-events: none;
}

.tab-divider__line {
  width: var(--dimension-stroke-width-012);
  height: var(--typography-lineheight-sm);
  flex-shrink: 0;
  background-color: var(--_tab-group-divider);
}

import { Component, Prop, Event, EventEmitter, Element, Listen, Watch, h, Host } from '@stencil/core';
import {
  getSelectableTabs,
  isTabDivider,
  type TabGroupItem,
  type TabItemTab,
} from './tab-item-utils';

export type TabBackground =
  | 'faint'
  | 'medium'
  | 'bold'
  | 'strong'
  | 'translucent'
  | 'inverted'
  | 'media'
  | 'always-dark';

@Component({
  tag: 'ds-tab-group',
  styleUrl: 'TabGroup.css',
  scoped: true,
})
export class TabGroup {
  @Element() el!: HTMLElement;

  @Prop({ mutable: true }) value: string = '';
  @Prop() tabs: TabGroupItem[] = [];
  @Prop() background: TabBackground | undefined;
  @Prop({ attribute: 'aria-label' }) ariaLabel: string | null = null;
  @Prop({ attribute: 'aria-labelledby' }) ariaLabelledby: string | undefined;

  @Event() dsChange!: EventEmitter<string>;

  private get selectableTabs(): TabItemTab[] {
    return getSelectableTabs(this.tabs);
  }

  private get focusableTabId(): string {
    return this.selectableTabs.some(tab => tab.id === this.value && !tab.isInactive)
      ? this.value
      : (this.selectableTabs.find(tab => !tab.isInactive)?.id ?? '');
  }

  private selectTab(id: string, options?: { focus?: boolean }) {
    this.value = id;
    this.dsChange.emit(id);
    if (options?.focus !== false) {
      this.focusTab(id);
    }
  }

  private focusTab(id: string) {
    const btn = this.el.querySelector(`[data-tab-id="${id}"]`) as HTMLElement | null;
    btn?.focus({ preventScroll: true });
  }

  /** Keep focus on the selected tab when value changes externally (e.g. BarNav menu). */
  @Watch('value')
  onValueChange(next: string, prev: string | undefined) {
    if (prev === undefined || next === prev) return;

    requestAnimationFrame(() => {
      const active = document.activeElement as HTMLElement | null;
      if (!active || !this.el.contains(active)) return;

      const activeId = active.getAttribute('data-tab-id');
      if (activeId === next) return;

      const focusId = this.selectableTabs.some(tab => tab.id === next && !tab.isInactive)
        ? next
        : this.focusableTabId;
      const nextTab = this.el.querySelector(`[data-tab-id="${focusId}"]`) as HTMLElement | null;
      if (nextTab) {
        nextTab.focus({ preventScroll: true });
      } else {
        active.blur();
      }
    });
  }

  /**
   * Find the next non-inactive tab index relative to `from`, stepping by `step`.
   * Returns `from` unchanged if no other enabled tab exists.
   */
  private findEnabled(from: number, step: 1 | -1): number {
    const tabs = this.selectableTabs;
    const len = tabs.length;
    for (let n = 0; n < len; n++) {
      const i = (from + step * (n + 1) + len * (n + 1)) % len;
      if (!tabs[i]?.isInactive) return i;
    }
    return from;
  }

  @Listen('keydown')
  handleKeyDown(e: KeyboardEvent) {
    const tabs = this.selectableTabs;
    if (!tabs.length) return;

    const focusedId = (e.target as Element | null)?.closest<HTMLElement>('[data-tab-id]')?.dataset['tabId'];
    const currentIdx = tabs.findIndex(t => t.id === (focusedId ?? this.focusableTabId));

    let nextIdx: number | null = null;

    if (e.key === 'ArrowRight') {
      nextIdx = this.findEnabled(currentIdx, 1);
    } else if (e.key === 'ArrowLeft') {
      nextIdx = this.findEnabled(currentIdx, -1);
    }

    if (e.key === 'Home') {
      const first = tabs.findIndex(t => !t.isInactive);
      nextIdx = first === -1 ? null : first;
    } else if (e.key === 'End') {
      const lastEnabled = [...tabs].reverse().findIndex(t => !t.isInactive);
      nextIdx = lastEnabled === -1 ? null : tabs.length - 1 - lastEnabled;
    }

    if (nextIdx !== null) {
      e.preventDefault();
      const next = tabs[nextIdx];
      this.selectTab(next.id);
    }
  }

  private getBgClass(): string {
    if (!this.background) return '';
    if (this.background === 'always-dark') return 'on-always-dark';
    return `on-${this.background}`;
  }

  render() {
    const bgClass = this.getBgClass();
    const focusableTabId = this.focusableTabId;

    return (
      <Host
        class={{
          'tab-group-host': true,
          'tab-group-host--surface': !!bgClass,
          [`tab-group-host--${bgClass}`]: !!bgClass,
        }}
      >
        <div
          role="tablist"
          class="tab-list"
          aria-label={this.ariaLabel}
          aria-labelledby={this.ariaLabelledby}
        >
          {this.tabs.map((tab, index) => {
            if (isTabDivider(tab)) {
              return (
                <div
                  key={`divider-${index}`}
                  class="tab-divider"
                  aria-hidden="true"
                >
                  <div class="tab-divider__line" />
                </div>
              );
            }

            const isSelected = tab.id === this.value;
            const variant = tab.variant ?? 'label';
            const showIcon = variant === 'icon' || variant === 'icon-label';
            const showLabel = variant === 'label' || variant === 'icon-label';
            const emphasizeLabel = isSelected && !bgClass;
            return (
              <button
                key={tab.id}
                type="button"
                role="tab"
                data-tab-id={tab.id}
                class={{
                  tab: true,
                  'tab--selected': isSelected,
                  'ds-control--sm': true,
                  'ds-focus-ring-inset': true,
                  'ds-interaction-fill': !tab.isInactive,
                  'ds-interaction-fill--on-faint': bgClass === 'on-faint',
                  'ds-interaction-fill--on-medium': bgClass === 'on-medium',
                  'ds-interaction-fill--on-bold': bgClass === 'on-bold',
                  'ds-interaction-fill--on-strong': bgClass === 'on-strong',
                  'ds-interaction-fill--on-translucent': bgClass === 'on-translucent',
                  'ds-interaction-fill--on-inverted': bgClass === 'on-inverted',
                  'ds-interaction-fill--on-media': bgClass === 'on-media',
                  'ds-interaction-fill--on-always-dark': bgClass === 'on-always-dark',
                  'ds-control-inactive': !!tab.isInactive,
                  [bgClass]: !!bgClass,
                }}
                aria-label={variant === 'icon' ? tab.label : undefined}
                aria-selected={isSelected}
                aria-disabled={tab.isInactive ? 'true' : undefined}
                aria-controls={tab.panelId ?? undefined}
                disabled={tab.isInactive}
                tabIndex={tab.id === focusableTabId ? 0 : -1}
                onClick={() => !tab.isInactive && this.selectTab(tab.id)}
              >
                <span class={{
                  tab__content: true,
                  [`tab__content--${variant}`]: true,
                  'tab__content--dot': !!tab.dot,
                }}>
                  {showIcon && (
                    <ds-icon
                      class="tab__icon"
                      name={tab.icon}
                      size="sm"
                      color="inherit"
                    />
                  )}
                  {showLabel && (
                    <ds-text
                      class="tab__label"
                      as="span"
                      variant="text-body-small"
                      emphasis={emphasizeLabel}
                      color="inherit"
                    >
                      {tab.label}
                    </ds-text>
                  )}
                  {tab.dot && (
                    <ds-badge
                      class="tab__dot"
                      variant="dot"
                      hasRing={false}
                      label=""
                      aria-hidden="true"
                    />
                  )}
                </span>
              </button>
            );
          })}
        </div>
      </Host>
    );
  }
}

export interface TabItemDivider {
  type: 'divider';
}

export interface TabItemTab {
  id: string;
  label: string;
  /** Disables the tab (same meaning as control `isInactive`). */
  isInactive?: boolean;
  /** id of the tabpanel this tab controls */
  panelId?: string;
  /** Show a notification dot (brand) on the tab — no count, matching panel-nav. */
  dot?: boolean;
}

export type TabItem = TabItemTab | TabItemDivider;

export type TabGroupItemVariant = 'label' | 'icon' | 'icon-label';

export interface TabGroupItemLabel extends TabItemTab {
  variant?: 'label';
  icon?: never;
}

export interface TabGroupItemIcon extends TabItemTab {
  variant: 'icon';
  icon: string;
}

export interface TabGroupItemIconLabel extends TabItemTab {
  variant: 'icon-label';
  icon: string;
}

export type TabGroupItem =
  | TabGroupItemLabel
  | TabGroupItemIcon
  | TabGroupItemIconLabel
  | TabItemDivider;

export function isTabDivider(item: TabItem): item is TabItemDivider {
  return 'type' in item && item.type === 'divider';
}

/** Tab entries that participate in selection, keyboard nav, and URL matching. */
export function getSelectableTabs(tabs: TabItem[]): TabItemTab[] {
  return tabs.filter((t): t is TabItemTab => !isTabDivider(t));
}
